  ('dietitian-moex-09424', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某公司研發一款新型體脂機，研發人員特別將此新型體脂機所測得之數據與一款已知能準確測量體脂肪 脂儀器之數據相比較，發現兩項數據相關性非常高。請問此種情形表示此儀器：', '["信度（reliability）高", "效度（validity）高", "敏感度（sensitivity）高", "特異性（specificity）高"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09425', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '病例對照（Case-control study）的營養流行病研究方法通常有下列那項缺點？', '["不適用於發生率較低的疾病研究", "無法得知患者個人的飲食攝取", "無法控制干擾因子（confounding factor）", "疾病的發生與病因在時序上有倒置現象"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09426', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '台灣地區老人營養健康狀況調查1999-2000調查結果指出，我國老人維生素B 之生化營養狀況約有多少 1 百分比是屬於缺乏？', '["5 %", "10 %", "15 %", "20 %"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09427', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據「台灣地區老人營養健康狀況調查1999-2000調查」結果，我國老人肥胖盛行率最高的地區為：', '["山地", "北部", "澎湖", "客家"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09428', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據「國小學童國民營養健康狀況變遷調查2001-2002調查」結果，我國國小男性學童每日蛋白質攝取量 約為建議攝取量之幾倍？', '["1", "1.5", "2", "2.5"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09429', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據「國小學童國民營養健康狀況變遷調查2001-2002調查」結果，我國學童肥胖之盛行率約為：', '["12 %", "15 %", "20 %", "24 %"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
