  ('dietitian-moex-09431', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '假設教育部在推行5年國民小學體重控制計畫之後，發現國內學童之肥胖盛行率由20 %降至12 %。請問 此種計畫評量方式，屬於何種評價：', '["效率（efficiency）", "效能（effectiveness）", "效果（effort）", "效益（benefit）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09432', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某營養師在策劃一項營養改善計畫時，將計畫對象依學生、成年婦女、更年期婦女加以區分後，再依各 族群特性分別訂定計畫內容。請問此種規劃方式稱為：', '["特殊化", "特質化", "市場區隔", "行銷組合"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09433', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某縣市正進行轄區內老人安養護機構相關需求量之規劃，請問以下那項慢性疾病數據對該項計畫最為適 用？', '["發生率", "盛行率", "勝算率", "罹患率"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
